import{_ as n,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Diff-Ansichten: Änderungen aus verschiedenen Perspektiven prüfen | Plannotator","description":"Lernen Sie, wie Sie in Plannotator Code-Reviews zwischen verschiedenen Diff-Typen wechseln. Wählen Sie im Dropdown-Menü zwischen uncommitted, staged, last commit oder branch-Ansicht, um Codeänderungen aus verschiedenen Perspektiven zu prüfen.","frontmatter":{"title":"Diff-Ansichten: Änderungen aus verschiedenen Perspektiven prüfen | Plannotator","sidebarTitle":"5 Diff-Ansichten wechseln","subtitle":"Diff-Ansichten: Änderungen aus verschiedenen Perspektiven prüfen","description":"Lernen Sie, wie Sie in Plannotator Code-Reviews zwischen verschiedenen Diff-Typen wechseln. Wählen Sie im Dropdown-Menü zwischen uncommitted, staged, last commit oder branch-Ansicht, um Codeänderungen aus verschiedenen Perspektiven zu prüfen.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"de/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"de/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),r={name:"de/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function s(d,e,o,l,h,c){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="diff-ansichten-wechseln" tabindex="-1">Diff-Ansichten wechseln <a class="header-anchor" href="#diff-ansichten-wechseln" aria-label="Permalink to &quot;Diff-Ansichten wechseln&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><p>Beim Code-Review können Sie:</p><ul><li>Über das Dropdown-Menü schnell zwischen 5 Diff-Ansichten wechseln</li><li>Verstehen, welchen Änderungsbereich jede Ansicht anzeigt</li><li>Je nach Prüfungsbedarf den passenden Diff-Typ auswählen</li><li>Vermeiden, dass wichtige Änderungen durch falsche Ansichtswahl übersehen werden</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><p><strong>Beim Review nur das Arbeitsverzeichnis geprüft und bereits gestagete Dateien übersehen</strong>:</p><p>Sie führen den Befehl <code>/plannotator-review</code> aus und sehen einige Codeänderungen, fügen ein paar Kommentare hinzu. Nach dem Commit stellen Sie fest, dass im Review die Dateien fehlen, die bereits mit <code>git add</code> in den Staging-Bereich verschoben wurden – diese Dateien erschienen gar nicht im Diff.</p><p><strong>Sie möchten den Gesamtunterschied zwischen aktuellem Branch und main-Branch sehen</strong>:</p><p>Sie entwickeln seit einigen Wochen auf einem Feature-Branch und möchten sehen, was insgesamt geändert wurde. Die Standard-Ansicht „Uncommitted changes&quot; zeigt aber nur die Änderungen der letzten Tage.</p><p><strong>Sie möchten die Unterschiede zwischen zwei bestimmten Commits vergleichen</strong>:</p><p>Sie möchten überprüfen, ob ein Bugfix korrekt ist und müssen den Code vor und nach der Korrektur vergleichen, wissen aber nicht, wie Sie Plannotator dazu bringen, den Diff historischer Commits anzuzeigen.</p><h2 id="wann-sie-diese-technik-anwenden" tabindex="-1">Wann Sie diese Technik anwenden <a class="header-anchor" href="#wann-sie-diese-technik-anwenden" aria-label="Permalink to &quot;Wann Sie diese Technik anwenden&quot;">​</a></h2><ul><li><strong>Bei umfassenden Reviews</strong>: Gleichzeitig Änderungen im Arbeitsverzeichnis und Staging-Bereich prüfen</li><li><strong>Vor dem Branch-Merge</strong>: Alle Änderungen des aktuellen Branches gegenüber main/master überprüfen</li><li><strong>Bei Rollback-Reviews</strong>: Bestätigen, welche Dateien beim letzten Commit geändert wurden</li><li><strong>Bei Teamarbeit</strong>: Code prüfen, den Kollegen gestaged aber noch nicht committet haben</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Der Git-Diff-Befehl hat viele Varianten, die jeweils unterschiedliche Codebereiche anzeigen. Plannotator fasst diese Varianten in einem Dropdown-Menü zusammen, sodass Sie sich keine komplexen Git-Befehle merken müssen.</p><div class="info custom-block"><p class="custom-block-title">Git Diff-Typen Übersicht</p><table tabindex="0"><thead><tr><th>Diff-Typ</th><th>Anzeigebereich</th><th>Typischer Anwendungsfall</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>Arbeitsverzeichnis + Staging</td><td>Alle Änderungen der aktuellen Entwicklung prüfen</td></tr><tr><td>Staged changes</td><td>Nur Staging-Bereich</td><td>Vor dem Commit die zu committenden Inhalte prüfen</td></tr><tr><td>Unstaged changes</td><td>Nur Arbeitsverzeichnis</td><td>Änderungen prüfen, die noch nicht mit <code>git add</code> hinzugefügt wurden</td></tr><tr><td>Last commit</td><td>Letzter Commit</td><td>Rollback oder Prüfung des gerade erfolgten Commits</td></tr><tr><td>vs main</td><td>Aktueller Branch vs. Standard-Branch</td><td>Umfassende Prüfung vor dem Branch-Merge</td></tr></tbody></table></div><p>Die Optionen im Dropdown-Menü ändern sich dynamisch je nach Ihrem Git-Status:</p><ul><li>Wenn Sie nicht auf dem Standard-Branch sind, erscheint die Option „vs main&quot;</li><li>Wenn keine Dateien gestaged sind, zeigt die Staged-Ansicht „No staged changes&quot;</li></ul><h2 id="schritt-fur-schritt" tabindex="-1">Schritt für Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt für Schritt&quot;">​</a></h2><h3 id="schritt-1-code-review-starten" tabindex="-1">Schritt 1: Code-Review starten <a class="header-anchor" href="#schritt-1-code-review-starten" aria-label="Permalink to &quot;Schritt 1: Code-Review starten&quot;">​</a></h3><p><strong>Warum</strong></p><p>Sie müssen zuerst die Code-Review-Oberfläche von Plannotator öffnen.</p><p><strong>Aktion</strong></p><p>Führen Sie im Terminal aus:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong></p><p>Der Browser öffnet die Code-Review-Seite. Über dem Dateibaum auf der linken Seite befindet sich ein Dropdown-Menü, das den aktuellen Diff-Typ anzeigt (normalerweise „Uncommitted changes&quot;).</p><h3 id="schritt-2-zur-staged-ansicht-wechseln" tabindex="-1">Schritt 2: Zur Staged-Ansicht wechseln <a class="header-anchor" href="#schritt-2-zur-staged-ansicht-wechseln" aria-label="Permalink to &quot;Schritt 2: Zur Staged-Ansicht wechseln&quot;">​</a></h3><p><strong>Warum</strong></p><p>Um Dateien zu sehen, die bereits mit <code>git add</code> hinzugefügt, aber noch nicht committet wurden.</p><p><strong>Aktion</strong></p><ol><li>Klicken Sie auf das Dropdown-Menü über dem Dateibaum links</li><li>Wählen Sie „Staged changes&quot;</li></ol><p><strong>Was Sie sehen sollten</strong></p><ul><li>Wenn gestagete Dateien vorhanden sind, zeigt der Dateibaum diese Dateien</li><li>Wenn keine Dateien gestaged sind, zeigt der Hauptbereich: „No staged changes. Stage some files with git add.&quot;</li></ul><h3 id="schritt-3-zur-last-commit-ansicht-wechseln" tabindex="-1">Schritt 3: Zur Last Commit-Ansicht wechseln <a class="header-anchor" href="#schritt-3-zur-last-commit-ansicht-wechseln" aria-label="Permalink to &quot;Schritt 3: Zur Last Commit-Ansicht wechseln&quot;">​</a></h3><p><strong>Warum</strong></p><p>Um den gerade committeten Code zu prüfen und sicherzustellen, dass alles in Ordnung ist.</p><p><strong>Aktion</strong></p><ol><li>Öffnen Sie erneut das Dropdown-Menü</li><li>Wählen Sie „Last commit&quot;</li></ol><p><strong>Was Sie sehen sollten</strong></p><ul><li>Alle Dateien werden angezeigt, die beim letzten Commit geändert wurden</li><li>Der Diff-Inhalt zeigt die Unterschiede von <code>HEAD~1..HEAD</code></li></ul><h3 id="schritt-4-zur-vs-main-ansicht-wechseln-falls-verfugbar" tabindex="-1">Schritt 4: Zur vs main-Ansicht wechseln (falls verfügbar) <a class="header-anchor" href="#schritt-4-zur-vs-main-ansicht-wechseln-falls-verfugbar" aria-label="Permalink to &quot;Schritt 4: Zur vs main-Ansicht wechseln (falls verfügbar)&quot;">​</a></h3><p><strong>Warum</strong></p><p>Um alle Änderungen des aktuellen Branches gegenüber dem Standard-Branch zu sehen.</p><p><strong>Aktion</strong></p><ol><li>Prüfen Sie, ob im Dropdown-Menü die Option „vs main&quot; oder „vs master&quot; vorhanden ist</li><li>Falls ja, wählen Sie diese aus</li></ol><p><strong>Was Sie sehen sollten</strong></p><ul><li>Der Dateibaum zeigt alle unterschiedlichen Dateien zwischen aktuellem Branch und Standard-Branch</li><li>Der Diff-Inhalt zeigt die vollständigen Änderungen von <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Aktuellen Branch prüfen</p><p>Wenn Sie die Option „vs main&quot; nicht sehen, befinden Sie sich auf dem Standard-Branch. Mit folgendem Befehl können Sie den aktuellen Branch anzeigen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Wechseln Sie zu einem Feature-Branch und versuchen Sie es erneut:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><p>Bestätigen Sie, dass Sie Folgendes beherrschen:</p><ul><li>[ ] Sie können das Diff-Typ-Dropdown-Menü finden und öffnen</li><li>[ ] Sie verstehen den Unterschied zwischen „Uncommitted&quot;, „Staged&quot; und „Last commit&quot;</li><li>[ ] Sie erkennen, wann die Option „vs main&quot; erscheint</li><li>[ ] Sie wissen, welchen Diff-Typ Sie in welchem Szenario verwenden sollten</li></ul><h2 id="haufige-fallstricke" tabindex="-1">Häufige Fallstricke <a class="header-anchor" href="#haufige-fallstricke" aria-label="Permalink to &quot;Häufige Fallstricke&quot;">​</a></h2><h3 id="fallstrick-1-beim-review-nur-uncommitted-gepruft-und-staged-dateien-ubersehen" tabindex="-1">Fallstrick 1: Beim Review nur Uncommitted geprüft und Staged-Dateien übersehen <a class="header-anchor" href="#fallstrick-1-beim-review-nur-uncommitted-gepruft-und-staged-dateien-ubersehen" aria-label="Permalink to &quot;Fallstrick 1: Beim Review nur Uncommitted geprüft und Staged-Dateien übersehen&quot;">​</a></h3><p><strong>Symptom</strong></p><p>Nach dem Commit stellen Sie fest, dass im Review einige bereits gestagete Dateien fehlen.</p><p><strong>Ursache</strong></p><p>Die Uncommitted-Ansicht zeigt alle Änderungen im Arbeitsverzeichnis und Staging-Bereich (<code>git diff HEAD</code>), bereits gestagete Dateien sind ebenfalls enthalten.</p><p><strong>Lösung</strong></p><p>Wechseln Sie vor dem Review zur Staged-Ansicht und prüfen Sie diese, oder verwenden Sie die Uncommitted-Ansicht (enthält den Staging-Bereich).</p><h3 id="fallstrick-2-vor-dem-branch-merge-nicht-mit-main-verglichen" tabindex="-1">Fallstrick 2: Vor dem Branch-Merge nicht mit main verglichen <a class="header-anchor" href="#fallstrick-2-vor-dem-branch-merge-nicht-mit-main-verglichen" aria-label="Permalink to &quot;Fallstrick 2: Vor dem Branch-Merge nicht mit main verglichen&quot;">​</a></h3><p><strong>Symptom</strong></p><p>Nach dem Merge in main stellen Sie fest, dass unbeabsichtigte Änderungen eingeführt wurden.</p><p><strong>Ursache</strong></p><p>Sie haben nur die Commits der letzten Tage geprüft, nicht den gesamten Unterschied des Branches gegenüber main.</p><p><strong>Lösung</strong></p><p>Führen Sie vor dem Merge eine umfassende Prüfung mit der „vs main&quot;-Ansicht durch.</p><h3 id="fallstrick-3-annahme-dass-beim-ansichtswechsel-kommentare-verloren-gehen" tabindex="-1">Fallstrick 3: Annahme, dass beim Ansichtswechsel Kommentare verloren gehen <a class="header-anchor" href="#fallstrick-3-annahme-dass-beim-ansichtswechsel-kommentare-verloren-gehen" aria-label="Permalink to &quot;Fallstrick 3: Annahme, dass beim Ansichtswechsel Kommentare verloren gehen&quot;">​</a></h3><p><strong>Symptom</strong></p><p>Sie trauen sich nicht, den Diff-Typ zu wechseln, aus Angst, dass zuvor hinzugefügte Kommentare verschwinden.</p><p><strong>Ursache</strong></p><p>Missverständnis des Wechselmechanismus.</p><p><strong>Tatsächliche Situation</strong></p><p>Beim Wechsel des Diff-Typs behält Plannotator die vorherigen Kommentare bei – sie können weiterhin relevant sein, oder Sie können irrelevante Kommentare manuell löschen.</p><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Die 5 von Plannotator unterstützten Diff-Typen:</p><table tabindex="0"><thead><tr><th>Typ</th><th>Git-Befehl</th><th>Anwendungsfall</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Alle Änderungen der aktuellen Entwicklung prüfen</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Staging-Bereich vor dem Commit prüfen</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Änderungen im Arbeitsverzeichnis prüfen</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Rollback oder Prüfung des letzten Commits</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Umfassende Prüfung vor dem Branch-Merge</td></tr></tbody></table><p>Beim Wechsel der Ansicht gehen keine Kommentare verloren. Sie können dieselben oder neue Kommentare aus verschiedenen Perspektiven betrachten.</p><h2 id="vorschau-der-nachsten-lektion" tabindex="-1">Vorschau der nächsten Lektion <a class="header-anchor" href="#vorschau-der-nachsten-lektion" aria-label="Permalink to &quot;Vorschau der nächsten Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../advanced/url-sharing/">URL-Freigabe</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie Review-Inhalte in einer URL komprimieren und mit Kollegen teilen</li><li>Wie der Empfänger den geteilten Review-Link öffnet</li><li>Einschränkungen und Hinweise im Freigabemodus</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Diff-Typ-Definition</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Git-Kontext abrufen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Git Diff ausführen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Diff-Wechsel-Behandlung</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Diff-Optionen im Dateibaum rendern</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Wichtige Typen</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>getGitContext()</code>: Ruft den aktuellen Branch, Standard-Branch und verfügbare Diff-Optionen ab</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Führt den entsprechenden Git-Befehl basierend auf dem Diff-Typ aus</li></ul><p><strong>Wichtige API</strong>:</p><ul><li><code>POST /api/diff/switch</code>: Wechselt den Diff-Typ und gibt neue Diff-Daten zurück</li></ul></details>',83)])])}const m=n(r,[["render",s]]);export{u as __pageData,m as default};
